import { useState } from 'react'
import { useAuth } from '../context/AuthContext'

const mockArticles = [
  {
    id: 1,
    headline: "Global Markets Rally as Economic Indicators Show Strong Growth",
    subtitle: "Investors celebrate as major indices reach new heights",
    category: "Economics",
    image: "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=800&h=600&fit=crop",
    size: "large"
  },
  {
    id: 2,
    headline: "Championship Final Set for Next Weekend",
    subtitle: "Top teams prepare for the ultimate showdown",
    category: "Sports",
    image: "https://images.unsplash.com/photo-1574629810360-7efbbe195018?w=800&h=600&fit=crop",
    size: "medium"
  },
  {
    id: 3,
    headline: "New Film Breaks Box Office Records",
    subtitle: "Audiences flock to theaters for latest blockbuster",
    category: "Entertainment",
    image: "https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=800&h=600&fit=crop",
    size: "small"
  },
  {
    id: 4,
    headline: "International Summit Addresses Climate Change",
    subtitle: "World leaders commit to ambitious new targets",
    category: "International",
    image: "https://images.unsplash.com/photo-1611273426858-450d8e3c9fce?w=800&h=600&fit=crop",
    size: "medium"
  },
  {
    id: 5,
    headline: "Tech Innovation Transforms Healthcare Industry",
    subtitle: "AI-powered solutions revolutionize patient care",
    category: "Technology",
    image: "https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=800&h=600&fit=crop",
    size: "small"
  },
  {
    id: 6,
    headline: "Cultural Festival Celebrates Local Heritage",
    subtitle: "Community comes together for annual celebration",
    category: "Culture",
    image: "https://images.unsplash.com/photo-1514525253161-7a46d19cd819?w=800&h=600&fit=crop",
    size: "large"
  },
  {
    id: 7,
    headline: "Scientists Discover New Species in Deep Ocean",
    subtitle: "Marine biologists excited about groundbreaking find",
    category: "Science",
    image: "https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=800&h=600&fit=crop",
    size: "small"
  },
  {
    id: 8,
    headline: "Local Restaurant Wins Prestigious Award",
    subtitle: "Chef's innovative cuisine earns international recognition",
    category: "Lifestyle",
    image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=800&h=600&fit=crop",
    size: "medium"
  },
  {
    id: 9,
    headline: "Major Infrastructure Project Breaks Ground",
    subtitle: "City officials celebrate new transportation hub",
    category: "Local",
    image: "https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&h=600&fit=crop",
    size: "small"
  },
]

const categoryColors = {
  Sports: "bg-red-100 text-red-700",
  International: "bg-blue-100 text-blue-700",
  Economics: "bg-green-100 text-green-700",
  Entertainment: "bg-purple-100 text-purple-700",
  Technology: "bg-indigo-100 text-indigo-700",
  Science: "bg-cyan-100 text-cyan-700",
  Culture: "bg-amber-100 text-amber-700",
  Lifestyle: "bg-pink-100 text-pink-700",
  Local: "bg-teal-100 text-teal-700"
}

export default function NewsstandPage() {
  const { user } = useAuth()
  const [articles] = useState(mockArticles)

  const getUserName = () => {
    if (user?.email) {
      const name = user.email.split('@')[0]
      return name.charAt(0).toUpperCase() + name.slice(1)
    }
    return "Vivek"
  }

  return (
    <div className="isolate bg-cream-50 px-8 py-28 sm:py-36 lg:px-10 min-h-screen">
      <div className="mx-auto max-w-7xl">

        {/* Welcome Section */}
        <div className="mx-auto max-w-3xl text-center mb-12">
          <h1 className="text-balance text-4xl font-serif font-normal tracking-tight text-soft-blue-800 sm:text-5xl">
            Welcome back {getUserName()},
          </h1>
          <p className="mt-6 text-sm text-soft-blue-600">
            lets catch you up on what's been going on!
          </p>
        </div>

        {/* Pinterest Masonry Layout */}
        <div className="columns-1 sm:columns-2 lg:columns-4 gap-6 space-y-6">
          {articles.map((article) => (
            <div
              key={article.id}
              className="break-inside-avoid rounded-2xl shadow-sm border border-soft-blue-200 bg-white overflow-hidden hover:shadow-md transition-shadow group"
            >
              {/* Image */}
              <div className="relative w-full overflow-hidden">
                <img
                  src={article.image}
                  alt={article.headline}
                  className="w-full object-cover group-hover:scale-105 transition-transform duration-300 grayscale"
                />

                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent"></div>

                {/* Category */}
                <span
                  className={`absolute top-4 left-4 inline-flex items-center rounded-full px-3 py-1 text-xs font-medium ${
                    categoryColors[article.category]
                  }`}
                >
                  {article.category}
                </span>
              </div>

              {/* Text Content */}
              <div className="p-5">
                <h3 className="text-lg font-serif font-semibold text-soft-blue-800">
                  {article.headline}
                </h3>
                <p className="text-sm text-soft-blue-600 mt-2">
                  {article.subtitle}
                </p>
              </div>
            </div>
          ))}
        </div>

      </div>
    </div>
  )
}
